import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import './Login.css';

function Login() {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // Extra Validation: Check if password is exactly 8 characters
    if (formData.password.length !== 8) {
      alert("Error: Password must be exactly 8 characters long.");
      return;
    }

    console.log("Login Action Triggered:", formData);

    // Save session and redirect
    localStorage.setItem("isLoggedIn", "true");
    localStorage.setItem("userEmail", formData.email);
    
    alert("Login Successful! Redirecting...");
    navigate('/client-dashboard');
  };

  return (
    <div className="login-container">
      <div className="card shadow-lg login-card p-4">
        <h2 className="text-center fw-bold mb-4 text-primary">Login</h2>
        
        <form onSubmit={handleSubmit}>
          {/* Email Field */}
          <div className="mb-3">
            <label className="form-label fw-bold text-dark">Email Address</label>
            <input 
              type="email" 
              name="email" 
              className="form-control shadow-sm" 
              placeholder="example@mail.com"
              onChange={handleChange} 
              required 
            />
          </div>

          {/* Password Field with 8-character constraint */}
          <div className="mb-3">
            <label className="form-label fw-bold text-dark">Password</label>
            <input 
              type="password" 
              name="password" 
              className="form-control shadow-sm" 
              placeholder="8-digit password"
              onChange={handleChange} 
              required 
              minLength="8" 
              maxLength="8" 
            />
            <div className="form-text text-danger small">
              * Must be exactly 8 characters.
            </div>
          </div>

          {/* Submit Button */}
          <button type="submit" className="btn btn-primary w-100 fw-bold mt-3 py-2 shadow">
            Login Now
          </button>
        </form>

        <p className="text-center mt-4 small text-muted">
          Don't have an account? <Link to="/register" className="text-primary fw-bold text-decoration-none">Sign Up</Link>
        </p>
      </div>
    </div>
  );
}

export default Login;
